export default function NavbarIntranet() {
    const { t } = useTranslation();
    const [isMenuOpen, setIsMenuOpen] = React.useState(false);
    const location = useLocation();
    const navigate = useNavigate();
    const user = useSelector((state: RootState) => state.user);

    const menuItems = [
        { label: t("orders._name"), url: "/commands" },
        {
            label: t("customer._name"),
            url: "/clients",
            visible: user.role === "admin",
        },
        {
            label: t("products._name"),
            url: "/stocks",
            visible: user.role === "admin" || user.role === "gestionnaire",
        },
        {
            label: t("users._name"),
            url: "/users",
            visible: user.role === "admin",
        },
        {
            label: t("suppliers._name"),
            url: "/suppliers",
            visible: user.role === "admin" || user.role === "gestionnaire",
        },
        {
            label: t("carriers._name"),
            url: "/carriers",
            visible: user.role === "admin" || user.role === "gestionnaire",
        },
    ];

    const filteredMenuItems = menuItems.filter(
        (item) => item.visible !== false,
    );

    const selectedKey: React.Key =
        filteredMenuItems.find(
            (item) =>
                location.pathname === item.url ||
                location.pathname.startsWith(`${item.url}/`),
        )?.url || location.pathname;

    const handleTabChange = (key: Key) => {
        navigate(String(key));
    };

    return (
        <div>
            <div className="max-w-screen-xl m-auto flex flex-col">
                <Navbar
                    onMenuOpenChange={setIsMenuOpen}
                    maxWidth="xl"
                    className="bg-primary-500"
                >
                    <NavbarContent>
                        <NavbarBrand>
                            <Logo height={40} />
                        </NavbarBrand>
                        <NavbarMenuToggle
                            className="[&>span::before]:bg-white [&>span::after]:bg-white lg:hidden"
                            aria-label={isMenuOpen ? "Close menu" : "Open menu"}
                        />
                    </NavbarContent>
                    <NavbarMenu className="bg-primary-500">
                        {/*<UserAccountActivator />*/}
                        {filteredMenuItems.map((item) => (
                            <NavbarMenuItem key={item.url}>
                                <Link
                                    className="w-full text-white"
                                    href={item.url}
                                    size="lg"
                                >
                                    {item.label}
                                </Link>
                            </NavbarMenuItem>
                        ))}
                    </NavbarMenu>
                    <NavbarContent
                        className="hidden lg:flex"
                        as="div"
                        justify="end"
                    >
                        <UserAccountActivator />
                        <ToggleLanguage />
                    </NavbarContent>
                </Navbar>
                <Divider className="bg-primary-400" />
            </div>
            <div className="hidden lg:flex max-w-screen-xl m-auto">
                <Tabs
                    selectedKey={selectedKey}
                    onSelectionChange={handleTabChange}
                    aria-label="Options"
                    classNames={{
                        tabList: "gap-6 w-full relative rounded-none p-0 ",
                        cursor: "w-full bg-white",
                        tab: "max-w-fit px-4 h-10 ",
                        tabContent:
                            "group-data-[selected=true]:text-white text-primary-200",
                    }}
                    color="primary"
                    variant="underlined"
                >
                    {filteredMenuItems.map((item) => (
                        <Tab key={item.url} title={item.label} />
                    ))}
                </Tabs>
            </div>
            <div className="bg-primary-500 h-96 absolute inset-0 top-0 -z-10"></div>
        </div>
    );
}
